            <Button onClick={() => handleAnalyze('video')} disabled={!image || isAnalyzing} variant="secondary" className="flex-1" icon={Video}>Video</Button>
          </div>
        </Card>
        <Card className="p-8 bg-black dark:bg-zinc-900 text-white min-h-[400px]">
